328:   /**
329:    * @return vendor specific version of a factory.
330:    */
331:   static absl::optional<envoy::config::core::v3::BuildVersion>
332:   getFactoryVersion(absl::string_view name) {
333:     auto it = versionedFactories().find(name);
334:     if (it == versionedFactories().end()) {
335:       return absl::nullopt;
336:     }
337:     return it->second;
